(() => {
  const LOAD_TIMEOUT = 5000;
  let timeoutId;

  function addLoadedClass() {
    if (!document.body.classList.contains('loaded')) {
      requestAnimationFrame(() => {
        document.body.classList.add('loaded');

        // Cleanup: Remove event listeners, stop observer, and clear timeout
        document.removeEventListener('DOMContentLoaded', addLoadedClass);
        window.removeEventListener('load', addLoadedClass);
        observer.disconnect();
        clearTimeout(timeoutId);
      });
    }
  }

  function checkBackgroundImages() {
    const stageElement = document.querySelector('.stage');
    if (!stageElement) return Promise.resolve();

    const backgroundImageUrl = window.getComputedStyle(stageElement).backgroundImage;
    if (backgroundImageUrl === 'none') return Promise.resolve();

    return new Promise((resolve) => {
      const img = new Image();
      img.onload = resolve;
      img.onerror = resolve; // Resolve even on error to prevent blocking
      img.src = backgroundImageUrl.replace(/url\(['"]?(.*?)['"]?\)/, '$1');
    });
  }

  function handleLoad() {
    if (document.readyState === 'complete' || document.readyState === 'interactive') {
      checkBackgroundImages().then(addLoadedClass);
    } else {
      document.addEventListener('DOMContentLoaded', () => checkBackgroundImages().then(addLoadedClass));
      window.addEventListener('load', () => checkBackgroundImages().then(addLoadedClass));
    }
  }

  // Start load check
  handleLoad();

  // Fallback timeout in case events don't fire
  timeoutId = setTimeout(() => checkBackgroundImages().then(addLoadedClass), LOAD_TIMEOUT);

  // Improved observer: Stops observing once the page is ready
  const observer = new MutationObserver(() => {
    if (document.readyState === 'complete') {
      checkBackgroundImages().then(addLoadedClass);
    }
  });

  observer.observe(document.documentElement, { childList: true, subtree: true });
})();




